Add the `printTunnelBanner` helper function:

```typescript
async function printTunnelBanner(url: string): Promise<void> {
  try {
    const qrcode = await import('qrcode-terminal');

    console.log('  Tunnel:  ' + url);
    console.log('');

    // Generate QR code as string
    qrcode.generate(url, { small: true }, (qr: string) => {
      const lines = qr.split('\n');
      const maxWidth = Math.max(...lines.map(l => l.length));
      const boxWidth = Math.max(maxWidth + 4, url.length + 6);

      console.log(`  ${'\u250C'}${'\u2500'.repeat(boxWidth)}${'\u2510'}`);
      console.log(`  ${'\u2502'}  Remote Access${' '.repeat(boxWidth - 16)}${'\u2502'}`);
      console.log(`  ${'\u2502'}  ${url}${' '.repeat(boxWidth - url.length - 2)}${'\u2502'}`);
      console.log(`  ${'\u2502'}${' '.repeat(boxWidth)}${'\u2502'}`);

      for (const line of lines) {
        if (line.trim()) {
          console.log(`  ${'\u2502'}  ${line}${' '.repeat(boxWidth - line.length - 2)}${'\u2502'}`);
        }
      }

      console.log(`  ${'\u2502'}${' '.repeat(boxWidth)}${'\u2502'}`);
      console.log(`  ${'\u2502'}  Scan to open on mobile${' '.repeat(boxWidth - 24)}${'\u2502'}`);
      console.log(`  ${'\u2514'}${'\u2500'.repeat(boxWidth)}${'\u2518'}`);
      console.log('');
    });
  } catch {
    // QR code printing is non-critical; just print the URL
    console.log(`  Tunnel:  ${url}`);
  }
}
```

