});

describe('CORS with tunnel origin', () => {
  it('accepts requests with tunnel origin when tunnel is connected', async () => {
    mockStatus.enabled = true;
    mockStatus.connected = true;
    mockStatus.url = 'https://abc123.ngrok-free.app';

    const res = await request(app)
      .get('/api/health')
      .set('Origin', 'https://abc123.ngrok-free.app');

    expect(res.status).not.toBe(500); // CORS error would cause 500
    expect(res.headers['access-control-allow-origin']).toBe('https://abc123.ngrok-free.app');
  });

  it('rejects requests with tunnel origin when tunnel is not connected', async () => {
    mockStatus.enabled = false;
    mockStatus.connected = false;
    mockStatus.url = null;

    const res = await request(app)
      .get('/api/health')
      .set('Origin', 'https://abc123.ngrok-free.app');

    // CORS rejection results in no access-control-allow-origin header
    expect(res.headers['access-control-allow-origin']).toBeUndefined();
  });

  it('always accepts requests with localhost origin', async () => {
    const res = await request(app)
      .get('/api/health')
      .set('Origin', 'http://localhost:4242');

    expect(res.headers['access-control-allow-origin']).toBe('http://localhost:4242');
  });

  it('accepts requests without Origin header', async () => {
    const res = await request(app).get('/api/health');

    expect(res.status).toBe(200);
  });

  it('updates allowed origin when tunnel URL changes', async () => {
    // First request with old tunnel URL
    mockStatus.connected = true;
    mockStatus.url = 'https://old.ngrok-free.app';

    const res1 = await request(app)
      .get('/api/health')
      .set('Origin', 'https://old.ngrok-free.app');
    expect(res1.headers['access-control-allow-origin']).toBe('https://old.ngrok-free.app');

    // Tunnel URL changes
    mockStatus.url = 'https://new.ngrok-free.app';

    const res2 = await request(app)
      .get('/api/health')
      .set('Origin', 'https://new.ngrok-free.app');
    expect(res2.headers['access-control-allow-origin']).toBe('https://new.ngrok-free.app');

    // Old URL no longer accepted
    const res3 = await request(app)
      .get('/api/health')
      .set('Origin', 'https://old.ngrok-free.app');
    expect(res3.headers['access-control-allow-origin']).toBeUndefined();
  });
});
