      const handler = vi.fn();
      manager.on('status_change', handler);

      await manager.stop();

      expect(handler).toHaveBeenCalledWith(
        expect.objectContaining({
          enabled: false,
          connected: false,
          url: null,
        }),
      );
    });

    it('passes on_status_change callback to ngrok.forward()', async () => {
      await manager.start({ port: 4242 });

      expect(capturedOnStatusChange).toBeTypeOf('function');
    });
  });

  describe('on_status_change callback', () => {
