      await manager.start({ port: 4242 });

      const handler = vi.fn();
      manager.on('status_change', handler);
      handler.mockClear();

      // Simulate ngrok disconnect
      capturedOnStatusChange!('', 'closed');

      expect(handler).toHaveBeenCalledWith(
        expect.objectContaining({
          connected: false,
          url: null,
        }),
      );
    });

    it('emits status_change with connected: true on reconnect', async () => {
      await manager.start({ port: 4242 });

      // Simulate disconnect
      capturedOnStatusChange!('', 'closed');

      const handler = vi.fn();
      manager.on('status_change', handler);

      // Simulate reconnect
      capturedOnStatusChange!('https://reconnected.ngrok.io', 'connected');

      expect(handler).toHaveBeenCalledWith(
        expect.objectContaining({
          connected: true,
          url: 'https://reconnected.ngrok.io',
        }),
      );
    });

    it('handles full disconnect-reconnect cycle', async () => {
      await manager.start({ port: 4242 });
      expect(manager.status.connected).toBe(true);

      capturedOnStatusChange!('', 'closed');
      expect(manager.status.connected).toBe(false);
      expect(manager.status.url).toBeNull();

      capturedOnStatusChange!('https://new.ngrok.io', 'connected');
      expect(manager.status.connected).toBe(true);
      expect(manager.status.url).toBe('https://new.ngrok.io');
    });
  });
});
