### New File: `apps/client/src/layers/shared/lib/__tests__/broadcast-channel.test.ts`

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { createChannel } from '../broadcast-channel';

// Mock BroadcastChannel in Node/jsdom environment
class MockBroadcastChannel {
  name: string;
  private listeners: Map<string, Set<Function>> = new Map();
  static instances: MockBroadcastChannel[] = [];

  constructor(name: string) {
    this.name = name;
    MockBroadcastChannel.instances.push(this);
  }

  postMessage(data: unknown) {
    // Broadcast to other instances with the same name
    for (const instance of MockBroadcastChannel.instances) {
      if (instance !== this && instance.name === this.name) {
        const handlers = instance.listeners.get('message');
        if (handlers) {
          handlers.forEach((h) => h({ data }));
        }
      }
    }
  }

  addEventListener(type: string, handler: Function) {
    if (!this.listeners.has(type)) this.listeners.set(type, new Set());
    this.listeners.get(type)!.add(handler);
  }

  removeEventListener(type: string, handler: Function) {
    this.listeners.get(type)?.delete(handler);
  }

  close() {
    this.listeners.clear();
    const idx = MockBroadcastChannel.instances.indexOf(this);
    if (idx >= 0) MockBroadcastChannel.instances.splice(idx, 1);
  }
}

beforeEach(() => {
  MockBroadcastChannel.instances = [];
  (globalThis as unknown as Record<string, unknown>).BroadcastChannel = MockBroadcastChannel;
});

afterEach(() => {
  MockBroadcastChannel.instances = [];
});

describe('createChannel', () => {
  it('creates a channel that can post and receive messages', () => {
    const ch1 = createChannel<string>('test');
    const ch2 = createChannel<string>('test');

    const handler = vi.fn();
    ch2.onMessage(handler);

    ch1.postMessage('hello');

    expect(handler).toHaveBeenCalledWith('hello');

    ch1.close();
    ch2.close();
  });

  it('unsubscribe stops receiving messages', () => {
    const ch1 = createChannel<string>('test');
    const ch2 = createChannel<string>('test');

    const handler = vi.fn();
    const unsub = ch2.onMessage(handler);

    ch1.postMessage('first');
    expect(handler).toHaveBeenCalledTimes(1);

    unsub();
    ch1.postMessage('second');
    expect(handler).toHaveBeenCalledTimes(1);

    ch1.close();
    ch2.close();
  });

  it('close() stops all communication', () => {
    const ch1 = createChannel<string>('test');
    const ch2 = createChannel<string>('test');

    const handler = vi.fn();
    ch2.onMessage(handler);

    ch2.close();
    ch1.postMessage('after-close');

    expect(handler).not.toHaveBeenCalled();

    ch1.close();
  });

  it('returns no-op channel when BroadcastChannel is unavailable', () => {
    delete (globalThis as unknown as Record<string, unknown>).BroadcastChannel;

    const ch = createChannel<string>('test');
    const handler = vi.fn();

    // Should not throw
    ch.postMessage('test');
    const unsub = ch.onMessage(handler);
    unsub();
    ch.close();

    expect(handler).not.toHaveBeenCalled();
  });
});
```

