```typescript
// @vitest-environment jsdom
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { renderHook } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { useTunnelSync } from '../model/use-tunnel-sync';

// Mock BroadcastChannel
let broadcastHandler: ((event: MessageEvent) => void) | null = null;

class MockBroadcastChannel {
  addEventListener(_type: string, handler: (event: MessageEvent) => void) {
    broadcastHandler = handler;
  }
  removeEventListener() {
    broadcastHandler = null;
  }
  postMessage() {}
  close() { broadcastHandler = null; }
}

// Mock EventSource
let sseHandler: ((event: Event) => void) | null = null;

class MockEventSource {
  addEventListener(_type: string, handler: (event: Event) => void) {
    sseHandler = handler;
  }
  close() { sseHandler = null; }
}

beforeEach(() => {
  (globalThis as unknown as Record<string, unknown>).BroadcastChannel = MockBroadcastChannel;
  (globalThis as unknown as Record<string, unknown>).EventSource = MockEventSource;
});

afterEach(() => {
  broadcastHandler = null;
  sseHandler = null;
});

describe('useTunnelSync', () => {
  it('invalidates queries on BroadcastChannel message', () => {
    const queryClient = new QueryClient();
    const invalidateSpy = vi.spyOn(queryClient, 'invalidateQueries');

    const wrapper = ({ children }: { children: React.ReactNode }) => (
      <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    );

    renderHook(() => useTunnelSync(), { wrapper });

    // Simulate BroadcastChannel message
    if (broadcastHandler) {
      broadcastHandler(new MessageEvent('message', { data: {} }));
    }

    expect(invalidateSpy).toHaveBeenCalledWith({ queryKey: ['tunnel-status'] });
    expect(invalidateSpy).toHaveBeenCalledWith({ queryKey: ['config'] });
  });

  it('invalidates queries on SSE tunnel_status event', () => {
    const queryClient = new QueryClient();
    const invalidateSpy = vi.spyOn(queryClient, 'invalidateQueries');

    const wrapper = ({ children }: { children: React.ReactNode }) => (
      <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    );

    renderHook(() => useTunnelSync(), { wrapper });

    // Simulate SSE event
    if (sseHandler) {
      sseHandler(new Event('tunnel_status'));
    }

    expect(invalidateSpy).toHaveBeenCalledWith({ queryKey: ['tunnel-status'] });
    expect(invalidateSpy).toHaveBeenCalledWith({ queryKey: ['config'] });
  });

  it('cleans up on unmount', () => {
    const queryClient = new QueryClient();
    const wrapper = ({ children }: { children: React.ReactNode }) => (
      <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    );

    const { unmount } = renderHook(() => useTunnelSync(), { wrapper });
    unmount();

    expect(broadcastHandler).toBeNull();
    expect(sseHandler).toBeNull();
  });
});
```

